classdef BoundedSquareProblem < lmz.api.NonlinearEquationProblem
    %BOUNDEDSQUAREPROBLEM One bounded unknown and one affine residual.
    methods
        function obj=BoundedSquareProblem()
            model=lmztest.AnalyticModel();
            decision=lmz.schema.VariableSchema( ...
                lmz.schema.VariableSpec('x','DefaultValue',0.25, ...
                'LowerBound',0,'UpperBound',1,'Scale',1),'1.0.0');
            parameters=lmz.schema.VariableSchema();
            obj@lmz.api.NonlinearEquationProblem(model,'bounded_square', ...
                'nonlinear_equation',decision,parameters,[],struct());
        end

        function descriptor=getDescriptor(obj)
            descriptor=struct('schemaVersion','1.0.0','id',obj.Id, ...
                'version',obj.Version,'kind',obj.Kind, ...
                'implementationId','lmztest.bounded-square.v1', ...
                'implemented',true,'maturity','experimental', ...
                'validationStatus','tested','provenance', ...
                struct('source','deterministic-test-fixture'), ...
                'capabilities',struct('simulate',false,'solve',true, ...
                'continue',false,'optimize',false,'visualize',false, ...
                'animate',false,'parameterHomotopy',false, ...
                'branchFamilyScan',false), ...
                'modelId','analytic_test','modelVersion','1.0.0', ...
                'configuration',obj.Configuration);
        end

        function evaluation=evaluate(obj,u,p,context,includeSimulation) %#ok<INUSD>
            context.check();obj.DecisionSchema.validateVector(u);
            obj.ParameterSchema.validateVector(p);
            evaluation=lmz.data.ProblemEvaluation( ...
                lmz.data.ResidualBlock('bounded_affine',u(1)-0.5,1));
        end

        function value=optionalJacobian(~,varargin) %#ok<INUSD>
            value=1;
        end
    end
end
